//帮别人调
#include <iostream>
using namespace std;
int m;
string n;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);
    bool flag = false;//记录前面是否有大于1的位 
    cin >> m >> n;
    int w = n.size()-1;
    for (int i = 0;i < n.size();i++){//从左往右遍历 
        if (n[i] != '0'){
        	if (flag == true)
				cout << "+";//如果前面有则输出+ 
			else
				flag = true;//否则flag为true 
            cout << n[i] << "*" << m << "^" << w;
        }
        w--;
    }
    cout << endl;
    return 0;
}
